final class DefaultXmlConfigService extends XmlConfigService {
  override def parseSettings(xml: String): Either[Throwable, ConfigSettings] = {
    try {
      val root = XML.loadString(xml)
      val settings =
        (root \\ "setting").flatMap { node =>
          val key = (node \@ "key").trim
          val value = node.text.trim
          if (key.nonEmpty) Some(key -> value) else None
